type FieldSource struct {
	Kind      SourceKind
	Column    string         // for SourceColumn, SourceTSVector, SourceGeo
	JSONBPath []string       // for SourceJSONBPath; first element is the top-level data key
	ValueType JSONBValueType // relevant for SourceJSONBPath
}

// SQLRef returns the bare SQL reference to the field value.
// For JSONB paths it returns `data #>> '{k1,k2,...}'` (text extraction).
// For all other source kinds it returns the column name.
func (s FieldSource) SQLRef() string {
	if s.Kind == SourceJSONBPath {
		return fmt.Sprintf("data #>> '{%s}'", strings.Join(s.JSONBPath, ","))
	}
	return s.Column
}

// SQLRefAs wraps SQLRef in a cast: `(data #>> '{...}')::castType`.
func (s FieldSource) SQLRefAs(castType string) string {
	return fmt.Sprintf("(%s)::%s", s.SQLRef(), castType)
}

// sqlCastType maps a JSONBValueType to the PostgreSQL cast keyword used in SQL expressions.
func sqlCastType(vt JSONBValueType) string {
	switch vt {
	case JSONBInteger:
		return "integer"
	case JSONBNumeric:
		return "numeric"
	case JSONBBoolean:
		return "boolean"
	default:
		return "text"
	}
}
